async function generateTryOn() {
  if (!userPhotoB64 || !selectedProduct) return;

  if (!App.isLoggedIn() && !App.isGuest()) {
    App.toast('Please sign in or continue as guest', true);
    window.location.href = 'login.html';
    return;
  }

  const loading = document.getElementById('loadingOverlay');
  const resultImg = document.getElementById('resultImg');
  const placeholder = document.getElementById('resultPlaceholder');
  const actions = document.getElementById('resultActions');

  loading.style.display = 'flex';
  placeholder.style.display = 'none';
  resultImg.style.display = 'none';

  try {
    const data = await App.api('/tryon', {
      method: 'POST',
      body: JSON.stringify({
        product_id: selectedProduct.product_id,
        source_image: userPhotoB64,
      }),
    });

    const session = data.tryon_session;
    resultImg.src = session.result_url;
    resultImg.style.display = 'block';
    actions.style.display = 'flex';
    App.toast('Try-on generated successfully');
  } catch (err) {
    // Demo fallback — show a placeholder result
    resultImg.src = selectedProduct.image_url || '';
    resultImg.style.display = 'block';
    actions.style.display = 'flex';
    App.toast('Demo mode — connect API for real results', true);
  } finally {
    loading.style.display = 'none';
  }
}

function downloadResult() {
  const img = document.getElementById('resultImg');
  if (!img.src) return;
  const a = document.createElement('a');
  a.href = img.src;

// ── Product Selector ──
async function loadProductSelector() {
  const products = await loadProducts();
  const selector = document.getElementById('productSelector');

  // Pre-select from URL param
  const urlProduct = new URLSearchParams(window.location.search).get('product');

  selector.innerHTML = products.map(p => `
    <div class="product-selector__item ${p.product_id === urlProduct ? 'selected' : ''}"
         onclick="selectProduct('${p.product_id}')" data-id="${p.product_id}">
      <img src="${p.image_url || ''}" alt="${p.name}" loading="lazy"
           onerror="this.style.display='none'">
      <div class="product-selector__name">${p.name}</div>
    </div>
  `).join('');

  App.products = products;
  if (urlProduct) selectProduct(urlProduct);
}

function selectProduct(id) {
  selectedProduct = App.products.find(p => p.product_id === id) || null;
  document.querySelectorAll('.product-selector__item').forEach(el => {
    el.classList.toggle('selected', el.dataset.id === id);
  });
  updateGenerateBtn();
}

