.product-selector {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 12px;
  margin-top: 16px;
  max-height: 400px;
  overflow-y: auto;
}
.product-selector__item {
  aspect-ratio: 3/4;
  background: var(--grey-100);
  overflow: hidden;
  cursor: pointer;
  border: 2px solid transparent;
  transition: border-color 0.2s;
  position: relative;
  min-height: 0;
}
.product-selector__item:hover { border-color: var(--grey-400); }
.product-selector__item.selected { border-color: var(--red); }
.product-selector__item img { width: 100%; height: auto; object-fit: cover; aspect-ratio: 3/4; display: block; }
.product-selector__name {
  position: absolute; bottom: 0; left: 0; right: 0;
  padding: 8px;
  background: linear-gradient(transparent, rgba(0,0,0,0.7));
  font-size: var(--text-xs);
  color: var(--white);
  font-weight: 500;
}

.tryon-layout {
  padding-top: 96px;
  display: grid;
  grid-template-columns: 1fr 1fr;
  min-height: 100vh;
  gap: 0;
}
.tryon-panel {
  padding: 48px;
  display: flex; flex-direction: column;
}
.tryon-panel--left { border-right: 1px solid var(--grey-200); }
.tryon-panel__title {
  font-family: var(--font-display);
  font-size: var(--text-xl);
  margin-bottom: 8px;
}
.tryon-panel__desc {
  font-size: var(--text-sm);
  color: var(--grey-600);
  margin-bottom: 32px;
}

/* Upload zone */
.upload-zone {
  border: 1px dashed var(--grey-200);
  padding: 48px;
  text-align: center;
  cursor: pointer;
  transition: all 0.3s;
  flex: 1;
  display: flex; flex-direction: column;
  align-items: center; justify-content: center;
  min-height: 300px;
  position: relative;
  overflow: hidden;
}
.upload-zone:hover { border-color: var(--black); }
.upload-zone.has-image { border-style: solid; padding: 0; }
.upload-zone__icon {
  width: 48px; height: 48px;
  margin-bottom: 16px;
  stroke: var(--grey-400);
}
.upload-zone__text {
  font-size: var(--text-sm);
  color: var(--grey-600);
  margin-bottom: 8px;
}
.upload-zone__hint {
  font-size: var(--text-xs);
  color: var(--grey-400);
  text-transform: uppercase;
  letter-spacing: 0.1em;
}
.upload-zone__preview {
  width: 100%; height: 100%;
  object-fit: contain;
  background: var(--grey-100);
}
.upload-zone__actions {
  position: absolute; bottom: 16px; left: 16px; right: 16px;
  display: flex; gap: 8px;
}

/* Camera */
.camera-feed {
  width: 100%; height: 100%;
  object-fit: cover;
  background: var(--black);
}
.camera-controls {
  position: absolute; bottom: 24px;
  left: 50%; transform: translateX(-50%);
  display: flex; gap: 16px; align-items: center;
}
.camera-btn {
  width: 56px; height: 56px;
  border-radius: 50%;
  background: var(--red);
  border: 3px solid var(--white);
  transition: transform 0.2s;
}
.camera-btn:hover { transform: scale(1.1); }
.camera-btn--secondary {
  width: 40px; height: 40px;
  background: rgba(255,255,255,0.2);
  border: 1px solid rgba(255,255,255,0.4);
}

